import{_ as e,v as t,x as a,a1 as r}from"./chunks/framework.421d9b7b.js";const f=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"contents/Docs/1.Introduction.md","filePath":"contents/Docs/1.Introduction.md"}'),o={name:"contents/Docs/1.Introduction.md"},n=r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="arraytotree" tabindex="-1">arrayToTree <a class="header-anchor" href="#arraytotree" aria-label="Permalink to &quot;arrayToTree&quot;">​</a></h2><p>This method converts a flat node array into a tree structure.</p><p>The implementation of this method is to first convert the given node array into a mapping with the node ID as the key, and then traverse each node, find its parent node, and add it to the parent node&#39;s children property. Finally, the entire tree is constructed starting from the root node and the tree structure data is returned.</p><h3 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h3><p>It accepts two parameters:</p><ul><li><p><strong>Array</strong>: Flat node array</p></li><li><p><strong>Options</strong>: An optional parameter object that is used to configure the specific behavior of the conversion method</p><table><thead><tr><th>Parameter</th><th>Description</th><th>Type</th><th>Default Value</th></tr></thead><tbody><tr><td>childrenKey</td><td>Custom node children field name</td><td>string</td><td>&#39;children&#39;</td></tr><tr><td>idKey</td><td>Custom node ID field name</td><td>string</td><td>&#39;id&#39;</td></tr><tr><td>pidKey</td><td>Custom node parent ID field name</td><td>string</td><td>&#39;pid&#39;</td></tr></tbody></table></li></ul><h3 id="return-value" tabindex="-1">Return Value <a class="header-anchor" href="#return-value" aria-label="Permalink to &quot;Return Value&quot;">​</a></h3><p>Returns a tree-structured node array.</p><h3 id="complexity" tabindex="-1">Complexity <a class="header-anchor" href="#complexity" aria-label="Permalink to &quot;Complexity&quot;">​</a></h3><ul><li><p><strong>Time Complexity</strong></p><p>The time complexity of this method is O(n), where n is the length of the input array. In the method, the input array is traversed and a mapping from node ID to node is created, which takes O(n) time. Next, all nodes are traversed again, and they are added to the children array of their parent nodes, which also takes O(n) time. Therefore, the total time complexity is O(n).</p></li><li><p><strong>Space Complexity</strong></p><p>The space complexity of this method is O(n), where n is the length of the array. In the method, a mapping from node ID to node is created by traversing the array, and all nodes are stored in the mapping, so the space complexity is O(n). Then, all child nodes are added to the parentNode&#39;s children property by traversing all nodes in the mapping, which is also O(n) space complexity. Therefore, the space complexity of the arrayToTree method is O(n).</p></li></ul><h2 id="treetoarray" tabindex="-1">treeToArray <a class="header-anchor" href="#treetoarray" aria-label="Permalink to &quot;treeToArray&quot;">​</a></h2><p>This method converts tree-structured data into a flattened array.</p><p>The specific implementation of this method is based on the breadth-first traversal of the binary tree. For each node traversed, a series of processing is performed, such as storing all properties of the node in a new node object, deleting ignored properties, and calculating and adding properties that need to be added. After these processing, the node will be saved in a new form to an array, and finally all node information (including descendant nodes) contained in the array will be returned.</p><h3 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h3><p>It accepts two parameters:</p><ul><li><p><strong>Tree</strong>: Tree structure containing all nodes</p></li><li><p><strong>Options</strong>: An optional parameter object that is used to configure the specific behavior of the conversion method</p><table><thead><tr><th>Property</th><th>Description</th><th>Type</th><th>Default Value</th></tr></thead><tbody><tr><td>addFields</td><td>A list of field names and their corresponding attribute value calculation methods that need to be added</td><td>[{ fieldName: string;callback: (item) =&gt; any }]</td><td>[]</td></tr><tr><td>childrenKey</td><td>Key name of child node</td><td>string</td><td>&#39;children&#39;</td></tr><tr><td>ignoreFields</td><td>List of field names to be ignored</td><td>string[]</td><td>[]</td></tr><tr><td>needParentId</td><td>Whether to add the ID of the parent node of the node information</td><td>boolean</td><td>true</td></tr></tbody></table></li></ul><h3 id="return-value-1" tabindex="-1">Return Value <a class="header-anchor" href="#return-value-1" aria-label="Permalink to &quot;Return Value&quot;">​</a></h3><p>Returns an array containing all node information, including their own information and the information of their descendant nodes.</p><h3 id="complexity-1" tabindex="-1">Complexity <a class="header-anchor" href="#complexity-1" aria-label="Permalink to &quot;Complexity&quot;">​</a></h3><ul><li><p>Time Complexity</p><p>The time complexity of this method depends on the depth and number of nodes in the tree. In the worst case, if the tree is a balanced tree and each node has multiple child nodes, the time complexity is O(nlogn). In the case of a small tree height, even if each node has multiple child nodes, the time complexity is still O(n), where n is the number of nodes. The method uses a stack to implement iteration to reduce memory usage and nested call stacks. Therefore, the method can be efficiently implemented in most cases.</p></li><li><p>Space Complexity</p><p>The space complexity of this method is O(n), where n is the number of nodes in the tree. Because the implementation of the method does not use recursion, but uses iteration, and uses a stack to implement depth-first traversal. The maximum length of the node array stored in the stack is the depth of the tree, so the space complexity is O(n).</p></li></ul>',21),i=[n];function d(s,h,l,c,p,m){return t(),a("div",null,i)}const y=e(o,[["render",d]]);export{f as __pageData,y as default};
